import { createInsforgeServer } from "@/lib/insforge-server";
import { RenderNode } from "@/registry";
import { notFound } from "next/navigation";
import { Navbar } from "@/components/layout/Navbar";
import { Footer } from "@/components/layout/Footer";

export default async function LiveAppPage({ params }: { params: Promise<{ appId: string }> }) {
  const { appId } = await params;
  const supabase = await createInsforgeServer();
  const { data: { user } } = await supabase.auth.getUser();

  // Fetch the latest published configuration directly
  let rawConfig: unknown = null;

  if (process.env.NODE_ENV === "development" && !user) {
    // DEV BYPASS: Fake published state
    rawConfig = {
      app: "Published App Simulation",
      pages: [
        {
          components: [
            { type: "Header", title: "Live Published Route", size: "lg" },
            { type: "ButtonAction", label: "Interact", variant: "default" }
          ]
        }
      ]
    };
  } else {
    // Secure Database Read
    const { data: appData, error } = await supabase
      .from("apps")
      .select("published_config")
      .eq("id", appId)
      .single();

    if (error || !appData?.published_config) {
      return notFound();
    }
    rawConfig = appData.published_config;
  }

  return (
    <div className="min-h-screen flex flex-col bg-background">
      <Navbar />
      
      <main className="flex-1 w-full max-w-4xl mx-auto px-4 py-10 flex flex-col gap-8">
         <div className="bg-[#27C93F]/10 border border-[#27C93F]/30 text-[#27C93F] text-xs font-mono py-1.5 px-3 rounded-full self-start flex items-center mb-4 shadow-sm shadow-[#27C93F]/5">
           <span className="w-1.5 h-1.5 bg-[#27C93F] rounded-full mr-2 shadow-[0_0_8px_rgba(39,201,63,0.8)] animate-pulse" />
           Live Environment
         </div>
         
         {/* Live Execution Loop via Registry Engine */}
         <div className="flex flex-col gap-8 w-full pb-32">
           {(rawConfig as any)?.pages?.[0]?.components?.map((comp: unknown, i: number) => (
             <RenderNode key={i} config={comp} />
           ))}
         </div>
      </main>

      <Footer />
    </div>
  );
}

"use client";

import { useMemo, useState, useRef } from "react";
import { ConfigEditor } from "@/components/builder/ConfigEditor";
import { CopilotPanel } from "@/components/builder/CopilotPanel";
import { LivePreview } from "@/components/builder/LivePreview";
import { ValidationPanel } from "@/components/builder/ValidationPanel";
import { validateConfig } from "@/lib/validation";
import { Button } from "@/components/ui/button";
import { ArrowLeft, Save, Play, Loader2 } from "lucide-react";
import Link from "next/link";
import { useParams } from "next/navigation";


const defaultMockConfig = JSON.stringify({
  app: "Employee Control Center",
  pages: [
    {
      components: [
        {
          type: "Header",
          title: "Operations Hub",
          subtitle: "Manage fleet logistics and security incidents globally.",
          size: "lg"
        },
        {
          type: "Grid",
          columns: 3,
          gap: 6,
          items: [
            {
              type: "Card",
              title: "System Alerts",
              subtitle: "2 unresolved issues",
              footer: [
                { type: "ButtonAction", label: "View Logs", variant: "outline", icon: "search" }
              ]
            },
            {
              type: "Card",
              title: "Active Personnel",
              subtitle: "142 onboard",
              footer: [
                { type: "ButtonAction", label: "Message All", variant: "ghost", icon: "play" }
              ]
            },
            {
              type: "Card",
              title: "Fleet Status",
              subtitle: "All units nominal",
              footer: [
                { type: "ButtonAction", label: "Run Diagnostic", variant: "secondary", icon: "arrow-right" }
              ]
            }
          ]
        }
      ]
    }
  ]
}, null, 2);

export default function BuilderPage() {
  const params = useParams();
  const appId = params.appId as string;
  
  const [configStr, setConfigStr] = useState(() => {
     if (appId.includes("template-blank")) {
        return JSON.stringify({ app: "Untitled Template", pages: [] }, null, 2);
     }
     if (appId.includes("template-directory")) {
        return JSON.stringify({
          app: "Employee Directory",
          pages: [{
            components: [
              { type: "Header", title: "Corporate Hierarchy", subtitle: "Internal personnel management." },
              { type: "Grid", columns: 3, items: [
                { type: "Card", title: "Vipin", subtitle: "Admin", footer: [{ type: "ButtonAction", label: "View" }] },
                { type: "Card", title: "John Doe", subtitle: "Developer", footer: [{ type: "ButtonAction", label: "View" }] }
              ]}
            ]
          }]
        }, null, 2);
     }
     return defaultMockConfig;
  });
  const { errors, warnings } = useMemo(() => validateConfig(configStr), [configStr]);
  const [isSaving, setIsSaving] = useState(false);

  const handleSave = async () => {
    setIsSaving(true);
    try {
      await import("@/actions/apps").then(m => m.saveAppConfig(appId, configStr));
      // Show generic browser alert until we put Sonner into `layout.tsx`
      alert("App Config saved and Backend Schema Synced!");
    } catch (e: unknown) {
      alert("Failed to save: " + (e as Error).message);
    } finally {
      setIsSaving(false);
    }
  };

  const [isPublishing, setIsPublishing] = useState(false);
  // Using regular Link for push
  
  const handlePublish = async () => {
    setIsPublishing(true);
    try {
      await import("@/actions/apps").then(m => m.publishAppConfig(appId, configStr));
      window.location.href = `/apps/${appId}`;
    } catch (e: unknown) {
      alert("Publish Error: " + (e as Error).message);
    } finally {
      setIsPublishing(false);
    }
  };

  const handleApplyCopilotComponents = (newComponents: unknown[]) => {
    try {
      const currentConfig = JSON.parse(configStr);
      if (!currentConfig.pages) currentConfig.pages = [{}];
      currentConfig.pages[0].components = newComponents;
      setConfigStr(JSON.stringify(currentConfig, null, 2));
    } catch {
      alert("Failed to weave AI structure into layout.");
    }
  };

  const streamTemplateRef = useRef<string | null>(null);

  const handleStreamStart = () => {
    try {
      const currentConfig = JSON.parse(configStr);
      if (!currentConfig.pages) currentConfig.pages = [{}];
      currentConfig.pages[0].components = "<<<REPLACE>>>";
      streamTemplateRef.current = JSON.stringify(currentConfig, null, 2);
    } catch(e) {
      streamTemplateRef.current = JSON.stringify({ app: "AI Generated Template", pages: [{ components: "<<<REPLACE>>>" }] }, null, 2);
    }
  };

  const handleStream = (rawText: string) => {
    if (streamTemplateRef.current) {
      setConfigStr(streamTemplateRef.current.replace('"<<<REPLACE>>>"', rawText));
    }
  };

  return (
    <div className="flex flex-col h-screen w-full bg-background overflow-hidden">
      {/* Builder Toolbar */}
      <div className="h-14 border-b border-border bg-card shrink-0 flex items-center justify-between px-4">
        <div className="flex items-center gap-4">
          <Link href="/dashboard">
            <Button variant="ghost" size="icon" className="h-8 w-8 text-muted-foreground hover:text-foreground hover:bg-muted">
              <ArrowLeft className="h-4 w-4" />
            </Button>
          </Link>
          <div className="flex flex-col">
            <span className="text-sm font-bold text-foreground leading-tight">App Builder</span>
            <span className="text-[10px] text-muted-foreground font-mono">{appId}</span>
          </div>
        </div>
        <div className="flex items-center gap-3">
          <div className="hidden md:flex items-center text-xs text-muted-foreground mr-4">
             {errors.length > 0 ? (
               <span className="text-[#FF5F56] font-medium flex items-center before:content-[''] before:w-1.5 before:h-1.5 before:bg-[#FF5F56] before:rounded-full before:mr-2">Has Errors</span>
             ) : (
               <span className="text-[#27C93F] font-medium flex items-center before:content-[''] before:w-1.5 before:h-1.5 before:bg-[#27C93F] before:rounded-full before:mr-2">Ready</span>
             )}
          </div>
          <Button 
            variant="outline" 
            size="sm" 
            className="h-8 bg-muted border-border hover:bg-card hover:text-foreground font-medium text-xs transition-colors"
            onClick={handleSave}
            disabled={isSaving}
          >
            {isSaving ? <Loader2 className="w-3.5 h-3.5 mr-2 animate-spin" /> : <Save className="w-3.5 h-3.5 mr-2" />}
            Save Draft
          </Button>
          <Button 
            onClick={handlePublish}
            disabled={isPublishing}
            size="sm" 
            className="h-8 bg-brand hover:bg-brand-dark text-white font-medium text-xs shadow-md shadow-brand/20"
          >
            {isPublishing ? <Loader2 className="w-3.5 h-3.5 mr-2 animate-spin" /> : <Play className="w-3.5 h-3.5 mr-2 fill-current" />}
            Publish
          </Button>
        </div>
      </div>

      {/* Workspace Area */}
      <div className="flex-1 flex overflow-hidden">
        {/* Left Side: Editor & Validation */}
        <div className="w-1/2 flex flex-col min-w-[300px] border-r border-border bg-card/50">
          <div className="flex-1 min-h-0 relative">
             <ConfigEditor 
               value={configStr} 
               onChange={(val) => setConfigStr(val || "")} 
             />
             <CopilotPanel 
               onApply={handleApplyCopilotComponents} 
               onStreamStart={handleStreamStart}
               onStream={handleStream}
             />
          </div>
          <div className="h-48 shrink-0">
             <ValidationPanel errors={errors} warnings={warnings} />
          </div>
        </div>

        {/* Right Side: Live Preview */}
        <div className="w-1/2 min-w-[300px] bg-background">
          <LivePreview configStr={configStr} />
        </div>
      </div>
    </div>
  );
}

﻿import { redirect } from "next/navigation";
import { auth } from "@clerk/nextjs/server";
import { Loader2 } from "lucide-react";
import { Suspense } from "react";
import { Navbar } from "@/components/layout/Navbar";
import { Footer } from "@/components/layout/Footer";
import { StatsBar } from "@/components/dashboard/StatsBar";
import { AppGrid } from "@/components/dashboard/AppGrid";
import { RecentActivity } from "@/components/dashboard/RecentActivity";
import { getUserApps } from "@/actions/apps";

async function DashboardContent() {
  let { userId } = await auth();

  if (!userId && process.env.NODE_ENV === "development") {
    // DEV BYPASS: Supabase default SMTP rate limits magic links to 3/hour.
    // We inject a dummy user so you can still view the Dashboard UI locally!
    userId = "dev-test-user-123";
  } else if (!userId) {
    redirect("/login");
  }

  const apps = (await getUserApps()) as any[];

  return (
    <div className="min-h-screen flex flex-col bg-background">
      <Navbar />
      
      <main className="flex-1 w-full max-w-7xl mx-auto px-4 py-10 flex flex-col gap-10">
        
        {/* Header section */}
        <div className="flex flex-col md:flex-row md:items-end justify-between gap-4">
          <div>
            <h1 className="text-3xl font-bold tracking-tight text-foreground">Creator Dashboard</h1>
            <p className="text-muted-foreground mt-1">Welcome back. Here is an overview of your AppForge ecosystem.</p>
          </div>
          <div className="text-xs font-mono bg-muted px-3 py-1.5 rounded-md border border-border text-muted-foreground">
            User ID: {userId?.split('_')[1]?.substring(0, 5) || "MOCK"}***
          </div>
        </div>

        {/* Stats Strip */}
        <StatsBar />

        {/* Main Layout Area */}
        <div className="grid grid-cols-1 xl:grid-cols-4 gap-8 mb-10">
          
          <div className="col-span-1 xl:col-span-3 h-full">
            <h2 className="text-lg font-bold text-foreground mb-5 uppercase tracking-wider text-xs">Your Apps</h2>
            <AppGrid initialApps={apps} />
          </div>

          <div className="col-span-1 xl:col-span-1 border-t xl:border-t-0 pt-8 xl:pt-0">
            <h2 className="text-lg font-bold text-foreground mb-5 uppercase tracking-wider text-xs xl:invisible hidden xl:block">Activity</h2>
            <div className="sticky top-6">
              <RecentActivity />
            </div>
          </div>
          
        </div>
        
      </main>

      <Footer />
    </div>
  );
}

export default function DashboardPage() {
  return (
    <Suspense fallback={<div className="flex h-screen w-full items-center justify-center bg-black"><Loader2 className="w-8 h-8 text-neutral-500 animate-spin" /></div>}>
      <DashboardContent />
    </Suspense>
  );
}

